const text = ($json.user_text || '').trim();
const memory = $json.chat_memory || [];

// Welcome Menu Mapping
const welcomeMap = {
  "1": "Angst und innere Unruhe",
  "2": "Schwere und Trauer",
  "3": "Wut und innere Anspannung",
  "4": "Konzentration fehlt",
  "5": "Orientierungslosigkeit",
  "6": "Kopf dreht sich zu viel",
  "7": "Erschöpfung und Antriebslosigkeit",
  "8": "Körper fühlt sich blockiert an",
  "9": "Bewegung und Aktivierung"
};

// Letzte Assistenten-Nachricht finden
const lastAssistant = [...memory].reverse().find(m => m.assistant)?.assistant || "";

// Optionen aus letzter Nachricht extrahieren
const optionLines = lastAssistant.split("\n").filter(l => /^[1-9]\s?—/.test(l.trim()));

let resolvedText = text;
let isCeremonyNumber = false;

if (/^[1-9]$/.test(text)) {
  const index = parseInt(text) - 1;
  if (optionLines.length > 0 && optionLines[index]) {
    resolvedText = optionLines[index].replace(/^[1-9]\s?—\s?/, "").trim();
  } else if (welcomeMap[text]) {
    resolvedText = welcomeMap[text];
    isCeremonyNumber = true;
  }
}

return [{
  json: {
    ...$json,
    user_text: resolvedText,
    ceremony_mode: isCeremonyNumber ? true : ($json.ceremony_mode || false)
  }
}];
